{
  "sentences": [
    {
      "text": "昨天我買菜了。",
      "pinyin": "Zuótiān wǒ mǎi cài le.",
      "pinyin_numeric": "zuo2tian1 wo3 mai3 cai4 le0",
      "translation_en": "I bought groceries yesterday.",
      "translation_ko": "어제 저는 장을 봤어요."
    },
    {
      "text": "上個禮拜他煮飯了。",
      "pinyin": "Shàng ge lǐbài tā zhǔ fàn le.",
      "pinyin_numeric": "shang4 ge0 li3bai4 ta1 zhu3 fan4 le0",
      "translation_en": "He cooked last week.",
      "translation_ko": "지난주에 그가 밥을 지었어요."
    },
    {
      "text": "昨天我們看電影了。",
      "pinyin": "Zuótiān wǒmen kàn diànyǐng le.",
      "pinyin_numeric": "zuo2tian1 wo3men0 kan4 dian4ying3 le0",
      "translation_en": "We watched a movie yesterday.",
      "translation_ko": "어제 우리는 영화를 봤어요."
    },
    {
      "text": "上個月她學中文了。",
      "pinyin": "Shàng ge yuè tā xué Zhōngwén le.",
      "pinyin_numeric": "shang4 ge0 yue4 ta1 xue2 Zhong1wen2 le0",
      "translation_en": "She studied Chinese last month.",
      "translation_ko": "지난달에 그녀는 중국어를 배웠어요."
    },
    {
      "text": "昨天我打掃家了。",
      "pinyin": "Zuótiān wǒ dǎsǎo jiā le.",
      "pinyin_numeric": "zuo2tian1 wo3 da3sao3 jia1 le0",
      "translation_en": "I cleaned the house yesterday.",
      "translation_ko": "어제 저는 집을 청소했어요."
    },
    {
      "text": "上個禮拜他運動了。",
      "pinyin": "Shàng ge lǐbài tā yùndòng le.",
      "pinyin_numeric": "shang4 ge0 li3bai4 ta1 yun4dong4 le0",
      "translation_en": "He exercised last week.",
      "translation_ko": "지난주에 그는 운동했어요."
    },
    {
      "text": "昨天我們散步了。",
      "pinyin": "Zuótiān wǒmen sànbù le.",
      "pinyin_numeric": "zuo2tian1 wo3men0 san4bu4 le0",
      "translation_en": "We took a walk yesterday.",
      "translation_ko": "어제 우리는 산책했어요."
    },
    {
      "text": "上個月她上班了。",
      "pinyin": "Shàng ge yuè tā shàngbān le.",
      "pinyin_numeric": "shang4 ge0 yue4 ta1 shang4ban1 le0",
      "translation_en": "She went to work last month.",
      "translation_ko": "지난달에 그녀는 출근했어요."
    },
    {
      "text": "昨天我洗澡了。",
      "pinyin": "Zuótiān wǒ xǐzǎo le.",
      "pinyin_numeric": "zuo2tian1 wo3 xi3zao3 le0",
      "translation_en": "I took a shower yesterday.",
      "translation_ko": "어제 저는 샤워했어요."
    },
    {
      "text": "上個禮拜他看電視了。",
      "pinyin": "Shàng ge lǐbài tā kàn diànshì le.",
      "pinyin_numeric": "shang4 ge0 li3bai4 ta1 kan4 dian4shi4 le0",
      "translation_en": "He watched TV last week.",
      "translation_ko": "지난주에 그는 텔레비전을 봤어요."
    }
  ]
}
